SELECT co.companyid, co.companyname, COUNT(b.id) AS branches
FROM companies co LEFT JOIN branches b ON b.company_id = co.id
WHERE co.companyid LIKE 'DEMO-%'
GROUP BY co.companyid, co.companyname ORDER BY branches DESC, co.companyid;